VALUES
  ('judicial-d35ec6db-moex-00187', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '有關刑法第16章之1妨害風化罪，下列敘述何者錯誤？', '["公然猥褻罪主觀上必須有意圖供人觀覽始成立犯罪", "與四親等之表妹發生性交，成立刑法第230條血親性交罪", "散布人獸交圖片，成立散布猥褻圖畫罪", "公務員犯包庇他人犯意圖使女子與他人為性交之行為，而媒介以營利罪，加重其刑至二分之一"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00188', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '政府三申五令禁止公務員涉足有女陪侍的酒店，在這些風化場所進行性交或猥褻的違法性交易行 為，所引發的刑法問題，下列敘述何者正確？', '["在封閉式包廂內陪侍之女性，可能觸犯刑法第234條公然猥褻罪", "陪侍女性主動引致性交易者，可能觸犯刑法第231條引誘營利罪", "開設酒店之人媒介性交易者，可能觸犯刑法第231條媒介營利罪", "公務員前往消費行為本身，即構成刑法第231條第2項包庇行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00189', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '甲因對其祖父乙索取金錢遭拒，憤而持花瓶丟向祖父乙，卻未丟中，有關甲之刑責為何？', '["傷害未遂罪", "義憤傷害未遂罪", "施強暴於直系血親尊親屬罪", "不成立犯罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00190', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '有關刑法第283條聚眾鬥毆罪的敘述，下列何者錯誤？', '["本罪罪質屬抽象危險犯", "致人於死或重傷，係屬客觀處罰條件", "本罪屬對向犯", "在場助勢者為本罪之行為人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00191', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '甲向學校老師威脅如果不給高分，就向學校誣告遭老師性騷擾，老師擔心無端受牽連只好給高分。 甲在刑法上成立何罪：', '["強制罪", "誹謗罪", "強制猥褻罪", "誣告罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00192', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '有關刑法第28章妨害秘密罪，下列敘述何者錯誤？', '["甲為知悉心儀已久之乙女所收到之信件內容，將信封置於燈下照射因而得知其內容，甲成立妨 害書信秘密罪", "里長甲因乙住家附近竊盜案件增加，故在人行道裝設監視器，因而錄得乙與男友在人行道接吻， 甲成立窺視竊聽竊錄罪", "甲在更衣室以遠端遙控隱藏鏡頭方式，錄影其他人更衣之情形，甲成立窺視竊聽竊錄罪", "甲將更衣室所竊錄的內容以網路傳送方式供不特定人下載，甲成立散布竊錄他人活動罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00193', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '甲於檳榔攤趁顧店小姐乙在後面收取包裹，無法看顧櫃檯時，將置於抽屜內之現金2,000元取走， 甲之刑事責任為何？', '["搶奪罪", "竊盜罪", "強制罪", "詐欺取財罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00194', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '甲與乙係兄弟，已成年分家未同住。甲因缺錢花用，未經乙同意，即將乙先前借給甲暫時使用之 機車1台，賣給中古機車行，得款新臺幣5,000元後，自行花用完畢。下列敘述何者正確？', '["甲構成竊盜罪", "甲所為犯罪因其與乙係兄弟，得免除其刑", "甲所為犯罪因其與乙係兄弟，須告訴乃論", "甲不構成犯罪，只需賠償乙新臺幣5,000元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00195', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '下列何者不是刑法第356條損害債權罪之構成要件？', '["債務人於將受強制執行之際", "債務人於強制執行後", "意圖損害債權人之債權", "毀壞、處分或隱匿其財產"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00196', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-2909f946', 'sub-judicial-d35ec6db-03', NULL, 'essay', '甲列乙為被告，訴請乙給付甲新臺幣（以下同）100萬元。甲主張乙於五
